function protectNames(s){
  var frag=document.createDocumentFragment();
  String(s).split(/(\s+)/).forEach(function(tok){
    if(/\w-\w/.test(tok)){var sp=el("span","nb");sp.textContent=tok;frag.appendChild(sp);}
    else frag.appendChild(document.createTextNode(tok));
  });
  return frag;
}
